def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = 1 / j
            power_term = ratio ** j
            if j % 2 == 0:
                power_term *= 1.1
            else:
                power_term *= 0.9
            score += weight * power_term
        if capacity < item * 2:
            score *= 1.5
            for k in range(1, 4):
                score += (k * 0.05)
        elif capacity > item * 5:
            score *= 0.75
            for k in range(3, 0, -1):
                score -= (k * 0.03)
        else:
            for m in range(1, 3):
                if (capacity / m) % 2 == 0:
                    score *= 1.05
                else:
                    score *= 0.95
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
